#!/usr/bin/env python3
import base64, os

files = {
    '/home/ec2-user/ccs/ccs-react/src/pages/chef/ChefPortal.tsx': '',
    '/home/ec2-user/ccs/ccs-react/src/pages/delivery/DeliveryPortal.tsx': '',
}

for path, encoded in files.items():
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, 'w') as f:
        f.write(base64.b64decode(encoded).decode())
    print(f"✅ {path}")

print("\nDone! Vite will hot-reload automatically.")
